func dayEvents(all []demo.CalendarEvent, day time.Time) []demo.CalendarEvent {
	var out []demo.CalendarEvent
	for _, e := range all {
		if sameDay(e.Date, day) {
			out = append(out, e)
		}
	}
	return out
}

func sameDay(a, b time.Time) bool {
	return a.Year() == b.Year() && a.Month() == b.Month() && a.Day() == b.Day()
}

